// =====================
// Process GitHub Profile
// =====================
const profile = $input.first().json;

const stats = {
  name: profile.name || 'mohammadmehrani',
  login: profile.login,
  bio: profile.bio,
  public_repos: profile.public_repos,
  followers: profile.followers,
  following: profile.following,
  total_stars: 0,
  total_forks: 0,
  top_languages: {},
  created_at: profile.created_at,
  updated_at: new Date().toISOString(),
  profile_url: profile.html_url,
  avatar_url: profile.avatar_url,
  blog: profile.blog,
  location: profile.location,
  twitter: profile.twitter_username,
  hireable: profile.hireable
};

const repos = $node['GitHub API - Repos'].all()[0].json;
if (Array.isArray(repos)) {
  repos.forEach(repo => {
    stats.total_stars += repo.stargazers_count || 0;
    stats.total_forks += repo.forks_count || 0;
    if (repo.language) {
      stats.top_languages[repo.language] = (stats.top_languages[repo.language] || 0) + 1;
    }
  });
}

// Sort languages by count
stats.top_languages = Object.entries(stats.top_languages)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 8)
  .reduce((acc, [lang, count]) => {
    acc[lang] = count;
    return acc;
  }, {});

return { stats };

// =====================
// Analyze GitHub Events
// =====================
const events = $input.all();
const analysis = {
  total_events: events.length,
  event_types: {},
  top_repos: {},
  recent_activity: [],
  push_count: 0,
  pr_count: 0,
  issue_count: 0,
  review_count: 0,
  daily_activity: null
};

// Process flat array of events
const flatEvents = events.reduce((acc, item) => {
  const data = item.json;
  if (Array.isArray(data)) {
    return acc.concat(data);
  }
  if (data.type) {
    acc.push(data);
  }
  return acc;
}, []);

flatEvents.forEach(event => {
  // Count event types
  analysis.event_types[event.type] = (analysis.event_types[event.type] || 0) + 1;

  // Count specific types
  if (event.type === 'PushEvent') analysis.push_count++;
  if (event.type === 'PullRequestEvent') analysis.pr_count++;
  if (event.type === 'IssuesEvent') analysis.issue_count++;
  if (event.type === 'PullRequestReviewEvent') analysis.review_count++;

  // Track repo activity
  const repoName = event.repo?.name || 'unknown';
  analysis.top_repos[repoName] = (analysis.top_repos[repoName] || 0) + 1;

  // Collect recent activity
  if (analysis.recent_activity.length < 5) {
    analysis.recent_activity.push({
      type: event.type,
      repo: repoName,
      time: event.created_at,
      action: event.payload?.action
    });
  }
});

// Sort repos by activity
analysis.top_repos = Object.entries(analysis.top_repos)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .reduce((acc, [repo, count]) => { acc[repo] = count; return acc; }, {});

// Calculate daily intensity
const now = new Date();
const todayEvents = flatEvents.filter(e => {
  const d = new Date(e.created_at);
  return d.toDateString() === now.toDateString();
});
analysis.daily_activity = todayEvents.length;

analysis.score = Math.min(100, (
  analysis.push_count * 2 +
  analysis.pr_count * 5 +
  analysis.issue_count * 3 +
  analysis.review_count * 4 +
  Math.min(analysis.daily_activity * 2, 20)
));

return { analysis };

// =====================
// Generate Smart Insights
// =====================
const stats = $node['Process Profile Data'].first().json.stats;
const analysis = $node['Analyze Activity'].first().json.analysis;
const historyRaw = $node['Redis Get History'].first().json?.data;

const history = historyRaw ? JSON.parse(historyRaw) : {
  snapshots: [],
  streak: 0,
  best_day: 0,
  last_updated: null
};

// Update history
history.snapshots.push({
  timestamp: new Date().toISOString(),
  followers: stats.followers,
  public_repos: stats.public_repos,
  total_stars: stats.total_stars,
  activity_score: analysis.score,
  daily_events: analysis.daily_activity
});

// Keep last 90 snapshots
if (history.snapshots.length > 90) {
  history.snapshots = history.snapshots.slice(-90);
}

// Calculate streak
const today = new Date().toDateString();
if (analysis.daily_activity > 0) {
  history.streak++;
} else {
  history.streak = 0;
}

// Track best day
if (analysis.daily_activity > history.best_day) {
  history.best_day = analysis.daily_activity;
}

history.last_updated = new Date().toISOString();

// Generate insights
const insights = [];

if (stats.followers > 0 && history.snapshots.length > 1) {
  const prev = history.snapshots[history.snapshots.length - 2];
  const followerGrowth = stats.followers - prev.followers;
  if (followerGrowth > 0) {
    insights.push(`📈 Follower growth: +${followerGrowth} since last check`);
  }
}

if (analysis.score >= 80) {
  insights.push('🔥 High activity day! Keep up the momentum!');
} else if (analysis.score <= 20) {
  insights.push('💤 Low activity detected. Time to code!');
}

if (history.streak > 0 && history.streak % 7 === 0) {
  insights.push(`🎯 ${history.streak}-day streak! Consistency is key!`);
}

// Language insight
const langs = Object.keys(stats.top_languages);
if (langs.length > 0) {
  insights.push(`🔤 Top language: ${langs[0]} (${stats.top_languages[langs[0]]} repos)`);
}

return { insights, history };

// =====================
// Format Stats for README
// =====================
const stats = $node['Process Profile Data'].first().json.stats;
const analysis = $node['Analyze Activity'].first().json.analysis;
const insights = $node['Generate Insights'].first().json.insights;

// Generate dynamic stats section
let statsSection = `
### 📊 GitHub Stats Snapshot

`;

statsSection += `| Metric | Value |\n|--------|-------|\n`;
statsSection += `| 📦 Repositories | ${stats.public_repos} |\n`;
statsSection += `| ⭐ Total Stars | ${stats.total_stars} |\n`;
statsSection += `| 🍴 Total Forks | ${stats.total_forks} |\n`;
statsSection += `| 👥 Followers | ${stats.followers} |\n`;
statsSection += `| 🔄 Following | ${stats.following} |\n`;
statsSection += `| 📨 Events Today | ${analysis.daily_activity} |\n`;
statsSection += `| ⚡ Activity Score | ${analysis.score}/100 |\n`;
statsSection += `| 🔥 Streak | ${insights.history ? insights.history.streak : 0} days |\n`;

if (Object.keys(stats.top_languages).length > 0) {
  statsSection += `\n**Top Languages:**\n`;
  Object.entries(stats.top_languages).forEach(([lang, count]) => {
    const bar = '█'.repeat(Math.min(count, 10));
    statsSection += `- ${lang}: ${bar} (${count})\n`;
  });
}

return { stats_markdown: statsSection, generated_at: new Date().toISOString() };

// =====================
// Generate Dynamic Badge
// =====================
const stats = $node['Process Profile Data'].first().json.stats;
const analysis = $node['Analyze Activity'].first().json.analysis;

const badgeData = {
  schemaVersion: 1,
  label: 'Activity',
  message: analysis.score >= 80 ? 'Very Active' :
           analysis.score >= 50 ? 'Active' :
           analysis.score >= 20 ? 'Moderate' : 'Quiet',
  color: analysis.score >= 80 ? 'brightgreen' :
         analysis.score >= 50 ? 'green' :
         analysis.score >= 20 ? 'yellow' : 'lightgrey',
  isError: false,
  namedLogo: 'github',
  logoSized: true
};

return { badge: badgeData };

